var doubleIt = function(head) {
    const nodes = [];
    let node = head;
    while (node !== null) {
        nodes.push(node);
        node = node.next;
    }
    let carry = 0;
    for (let i = nodes.length - 1; i >= 0; i--) {
        const total = nodes[i].val * 2 + carry;
        nodes[i].val = total % 10;
        carry = Math.floor(total / 10);
    }
    if (carry) {
        const newHead = new ListNode(carry);
        newHead.next = head;
        return newHead;
    }
    return head;
};
